112	  --z-statusbar: 50;
113	  --z-palette:   80;
114	  --z-toast:     90;
115	  --z-boot:     100;
116	
117	  /* motion vocabulary (suite 13/P04) — five durations, three curves.
118	     Functional motion only: every animation has a no-motion path via the
119	     reduced-motion block at the bottom of this file. See
120	     docs/v2_motion_guide.md for the use-case map. */
121	  --d-instant: 0ms;     /* state change with no animation        */
122	  --d-tap:     80ms;    /* button press feedback                 */
123	  --d-fast:    160ms;   /* focus ring, hover state               */
124	  --d-norm:    280ms;   /* page transition fade                  */
125	  --d-slow:    480ms;   /* chat message arrival                  */
126	
127	  --ease-out:    cubic-bezier(0.16, 1, 0.3, 1);    /* decelerate to rest */
128	  --ease-in-out: cubic-bezier(0.4, 0, 0.2, 1);     /* state toggles      */
129	  --ease-linear: linear;                            /* text streaming    */
130	
131	  /* legacy motion aliases (transitional) — components in src/components/*
132	     and src/_legacy_v1/* still reference --d-flash, --d-accordion, --ease,
133	     --ease-accordion. Aliased onto the v2 motion vocabulary so existing
134	     timings degrade gracefully until each component is migrated. New code
135	     MUST consume the v2 tokens above. */
136	  --d-flash:        var(--d-fast);
137	  --d-accordion:    var(--d-slow);
138	  --ease:           var(--ease-out);
139	  --ease-accordion: var(--ease-out);
140	
141	  /* layout */
142	  --statusbar-h: 0px; /* R04: status bar removed; reserved height collapses */
143	  --toprail-h:   32px;
144	  --keycap-size: 36px;
145	  --measure-prose: 72ch;
146	  --measure-book:  64ch;
147	
148	  color-scheme: dark;
149	}
